mapper.select:
SELECT * FROM sys_table_operation
WHERE table_code = #{tableCode}
ORDER BY sort_order

mapper.insert:
INSERT INTO sys_table_operation (
    table_code, operation_code, operation_name, operation_type,
    icon, permission, position, sort_order, status, menu_id,
    event_type, event_config, confirm_message
) VALUES (
    #{tableCode}, #{operationCode}, #{operationName}, #{operationType},
    #{icon}, #{permission}, #{position}, #{sortOrder}, #{status}, #{menuId},
    #{eventType}, #{eventConfig}, #{confirmMessage}
)
